const body = $input.item.json.body || $input.item.json;
const message = body.message || {};
const toolCall = (message.toolCalls || [])[0] || {};
const call = message.call || {};

let toolArgs = {};
try {
  toolArgs = JSON.parse(toolCall.function?.arguments || '{}');
} catch (e) {
  toolArgs = {};
}

return [{
  json: {
    toolCallId: toolCall.id || 'unknown',
    toolName: toolCall.function?.name || 'unknown',
    toolArgs,
    callId: call.id || 'unknown',
    customerPhone: call.customer?.number || '',
    timestamp: new Date().toISOString()
  }
}];

const toolCallId = $input.item.json.toolCallId;
const args = $input.item.json.toolArgs || {};
const date = args.date || 'your requested date';
const time = args.time || 'your requested time';

return [{
  json: {
    results: [{
      toolCallId: toolCallId,
      result: `I've noted your preference for ${date} at ${time}. Our team will contact you to confirm the exact slot. Would you like me to save your details now so we can reach you?`
    }]
  }
}];

const toolCallId = $('Extract Tool Call').first().json.toolCallId;
return [{
  json: {
    results: [{
      toolCallId: toolCallId,
      result: "Perfect, I've saved your appointment request details. A staff member will call you within 2 hours to confirm."
    }]
  }
}];

const toolCallId = $input.item.json.toolCallId;
return [{
  json: {
    results: [{
      toolCallId: toolCallId,
      result: "I'm unable to process that request right now. Please let me know how else I can help you."
    }]
  }
}];

// Use a Code node to safely extract the transcript.
// Raw JSON Set mode breaks when the transcript contains newlines or quotes.
const body = $input.item.json.body || $input.item.json;
const message = body.message || {};
const call = message.call || {};
const structuredData = message.analysis?.structuredData || {};

return [{
  json: {
    eventType: message.type || 'unknown',
    callId: call.id || 'unknown',
    callStatus: call.status || 'unknown',
    customerPhone: call.customer?.number || '',
    transcript: message.transcript || '',
    patientName: structuredData.patientName || '',
    patientPhone: structuredData.patientPhone || '',
    requestedDateTime: structuredData.requestedDateTime || '',
    reason: structuredData.reason || structuredData.appointmentReason || '',
    timestamp: new Date().toISOString()
  }
}];

